parameters.jsCode:
const lead = $input.first().json;
const phoneNumber = $('Extract Message').item.json.phoneNumber;
const userMessage = $('Extract Message').item.json.chatInput;
const sessionId = $('Extract Message').item.json.sessionId;
const nombre = lead.Nombre || 'cliente';

const chatInput = `[CONTEXTO INTERNO: Este cliente (${nombre}) YA ESTÁ REGISTRADO como Calificado. NO le pidas nombre, email ni datos. Salúdalo por su nombre, recuérdale que ya lo tienes registrado y que el equipo de ventas se pondrá en contacto. Responde sus preguntas/dudas. Si el cliente pide hablar con ventas o cotizar, NO inicies calificación — simplemente confirma que el equipo lo contactará. Si insiste en registrarse de nuevo, sugiérele escribir /reset.]\n\nMensaje del cliente: ${userMessage}`;

return [{ json: { phoneNumber, chatInput, sessionId, isCalificado: true } }];

const phoneNumber = $('Extract Message').item.json.phoneNumber;
const response = $input.first().json;
const rows = response?.values || [];
if (rows.length === 0) {
  return [{ json: { found: false, Estado: '', Nombre: '', phoneNumber } }];
}
const headers = rows[0];
const idIdx = headers.indexOf('Teléfono');
const estadoIdx = headers.indexOf('Estado');
const nombreIdx = headers.indexOf('Nombre');
if (idIdx === -1) {
  return [{ json: { found: false, Estado: '', Nombre: '', phoneNumber } }];
}
const norm = (p) => String(p || '').replace(/\D/g, '');
let found = null;
for (let i = 1; i < rows.length; i++) {
  if (norm(rows[i][idIdx]) === norm(phoneNumber)) {
    found = rows[i];
    break;
  }
}
if (!found) {
  return [{ json: { found: false, Estado: '', Nombre: '', phoneNumber } }];
}
return [{ json: {
  found: true,
  Estado: found[estadoIdx] || '',
  Nombre: found[nombreIdx] || '',
  phoneNumber
} }];

const { phoneNumber } = $input.first().json;
const wf = $getWorkflowStaticData('global');
if (!wf.humanMode) wf.humanMode = {};
const isPaused = wf.humanMode[phoneNumber] === true;
return [{ json: { ...$input.first().json, isPaused } }];

const { phoneNumber, senderName, cleanMessage, fechaCorta } = $input.first().json;
const wf = $getWorkflowStaticData('global');
if (!wf.humanMode) wf.humanMode = {};
if (!wf.humanModeAt) wf.humanModeAt = {};
wf.humanMode[phoneNumber] = true;
wf.humanModeAt[phoneNumber] = Date.now();

const history = (wf.history && wf.history[phoneNumber]) || [];
const historyText = history.length > 0 ? history.slice(-10).join('\n') : '(sin historial)';
const phoneFormatted = phoneNumber.startsWith('+') ? phoneNumber : '+' + phoneNumber;

const contextMessage = `--- Contexto WhatsApp ---\nNúmero: ${phoneNumber}\nNombre: ${senderName || 'Desconocido'}\nFecha: ${fechaCorta}\n\nHistorial:\n${historyText}\n\n⚠ El cliente solicitó hablar con un agente humano.`;

return [{ json: {
  phoneNumber,
  phoneFormatted,
  senderName: senderName || 'Cliente WhatsApp',
  cleanMessage,
  contextMessage,
  fechaCorta
} }];

const rawPhone = $input.first().json.phoneNumber || $input.first().json.body?.phoneNumber || '';
const phoneNumber = String(rawPhone).replace(/\D/g, '');
const wf = $getWorkflowStaticData('global');
if (!wf.resetEpochs) wf.resetEpochs = {};
if (phoneNumber) {
  wf.resetEpochs[phoneNumber] = Date.now();
  if (wf.humanMode) delete wf.humanMode[phoneNumber];
  if (wf.humanModeAt) delete wf.humanModeAt[phoneNumber];
}
return [{ json: { ok: true, phoneNumber } }];

const phone = $('Extract Message').item.json.phoneNumber;
const staticData = $getWorkflowStaticData('global');
const modeAt = staticData.inDesignerModeAt?.[phone] || 0;
const expired = (Date.now() - modeAt) > 86400000;
if (expired && staticData.inDesignerMode?.[phone]) {
  staticData.inDesignerMode[phone] = false;
  delete staticData.inDesignerModeAt[phone];
}
const inDesignerMode = staticData.inDesignerMode?.[phone] === true;
const designerEpoch = staticData.inDesignerModeAt?.[phone] || 0;
const designerSessionId = `${phone}-dise-${designerEpoch}`;
return { ...$json, inDesignerMode, designerSessionId };

const MAX_RENDERS = 2;
const phone = $json.phoneNumber || '';
const desc = ($json.descriptionFurniture || '').toLowerCase();

// Categorías permitidas
const ALLOWED = /cocina|closet|vestidor|bar|plafon|puerta|mueble|tv|lavaneta|carpinteria|repisa|alacena|isla|cajon|melamina|madera|gabinete|armario|vitrina|biblioteca/;

// Términos bloqueados
const BLOCKED = /pornograf|sex|desnud|arma|droga|coche|carro|persona|gente|retrato|cara|rostro|auto|vehiculo|animal|mascota/;

// Leer contador de renders del staticData
const renderData = $getWorkflowStaticData('global').renderData || {};
const clientData = renderData[phone] || { renderCount: 0 };

const isBlocked = BLOCKED.test(desc);
const isAllowed = ALLOWED.test(desc);
const overLimit = clientData.renderCount >= MAX_RENDERS;

const validRender = !isBlocked && isAllowed && !overLimit;

return {
  ...$json,
  validRender,
  renderCount: clientData.renderCount,
  bypassReason: isBlocked ? 'blocked_content' : (!isAllowed ? 'not_furniture' : (overLimit ? 'limit_reached' : null))
};

const desc = $json.descriptionFurniture || '';
const prompt = `Genera UNA imagen fotorrealista de un mueble fabricado por Reyna Cocinas y Carpinterías Finas (Monterrey, México), 37 años de oficio en carpintería fina.

Mueble solicitado por el cliente: "${desc}"

Usa las imágenes de referencia adjuntas como guía de estilo, materiales (melamina, madera natural, herrajes finos), acabados, iluminación cálida, composición de catálogo y nivel de detalle.

REGLAS ESTRICTAS:
- Solo muebles fijos a medida (cocinas, closets, vestidores, bares, plafones, puertas, muebles de TV, lavanetas).
- Sin personas, sin texto sobreimpreso, sin marcas de agua.
- Iluminación cálida tono 3000K, fondo neutro tono crema o gris claro.
- Composición centrada, tipo catálogo de carpintería profesional.`;
return { ...$json, geminiPrompt: prompt };

const prev = $('Preparar Prompt Render').item.json;
const parts = $input.item.json.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData?.mimeType?.startsWith('image/'));

if (!imagePart) {
  // Gemini bloqueó o falló — bypass
  return { ...prev, renderFailed: true, base64Image: null };
}

return {
  ...prev,
  renderFailed: false,
  base64Image: imagePart.inlineData.data,
  mimeType: imagePart.inlineData.mimeType
};

const phone = $json.phoneNumber;
const cloudinaryUrl = $json.secure_url;
const desc = $json.descriptionFurniture;
const top3Refs = $json.top3Refs || '';
const categoria = $json.top3?.[0]?.categoria || '';

// Actualizar staticData
const staticData = $getWorkflowStaticData('global');
if (!staticData.renderData) staticData.renderData = {};
if (!staticData.renderData[phone]) staticData.renderData[phone] = { renderCount: 0 };
staticData.renderData[phone].renderCount += 1;
staticData.renderData[phone].generatedImageUrl = cloudinaryUrl;
staticData.renderData[phone].lastDescription = desc;

return {
  ...$json,
  generatedImageUrl: cloudinaryUrl,
  renderCount: staticData.renderData[phone].renderCount
};

const REF_URLS = [
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935289/Vestidores__eju7zq.avif',
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935287/Vestidores_tgu8y1.avif',
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935282/mdtv_bsu7rc.avif',
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935275/Cocina_moderna_rdd4xb.avif',
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935273/Cocina_Madera_pz2rcf.avif',
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935263/bares__bwkutc.avif',
  'https://res.cloudinary.com/dqxjg4qlb/image/upload/f_jpg,q_85,w_1024/v1777935261/Bares_ex6ajd.avif'
];
return { ...$json, refUrls: REF_URLS };

const baseItem = $input.first()?.json || {};
const refs = baseItem.refUrls || [];
return refs.map((url, i) => ({
  json: { ...baseItem, refUrl: url, refIndex: i, refCount: refs.length }
}));

// Debug: ver qué hay realmente en $binary
const allBinaryKeys = Object.keys($binary || {});
const binDescriptor = $binary?.data;
const binDataValue = binDescriptor?.data;
const binMimeType = binDescriptor?.mimeType;

// Si hay data, usarla; si no, marcar debug
if (binDataValue) {
  return {
    ...$json,
    refMimeType: binMimeType || 'image/jpeg',
    refBase64: binDataValue
  };
} else {
  // Loguear para diagnóstico
  return {
    ...$json,
    refMimeType: binMimeType || 'image/jpeg',
    refBase64: null,
    _debugBinaryKeys: allBinaryKeys,
    _debugBinDescriptor: JSON.stringify(binDescriptor)
  };
}

const items = $input.all();
// Validar Tema preserva descriptionFurniture via ...spread
const origin = $('Validar Tema').first().json;
const refs = items
  .map(i => i.json)
  .filter(j => j.refBase64)
  .map(j => ({ inline_data: { mime_type: j.refMimeType, data: j.refBase64 } }));
return [{
  json: {
    ...origin,
    referenceParts: refs,
    refCountLoaded: refs.length
  }
}];
